window.__QUIZ_DATA__=[{"id":"objective>Chemistry>2002>1","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : RELATIVE ATOMIC MASS (AR) AND RELATIVE MOLECULAR MASS (MR) BASED ON CARBON-12 SCALE.","question":"If the relative molecular mass of an element is not a whole number . it can be deducted that the element is","images":[],"options":{"A":"naturally radioactive","B":"Abundant in nature","C":"a transition metal","D":"an isotopic mixture"},"answer":"D","explanation":"The relative atomic mass of an element is the average value of its isotopic mixture , it is the weighted average of masses of the atoms of he isotopes","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>2","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Th atom of an element X is represented as yzX  the basic chemical properties of X depends on the value of","images":[],"options":{"A":"Y","B":"Z","C":"Y-Z","D":"Z-Y"},"answer":"B","explanation":"The periodic law states that the properties of elements are periodic functon of their Atomic number (Z)","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>3","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"The atomic number of chlorine is 17. what is the number of electrons in a chlorine ion ?","images":[],"options":{"A":"16","B":"17","C":"18","D":"19"},"answer":"C","explanation":"A neutral atom of chlorine has 17 electrons since its atomic number is 17, its chlorine ion is formed when it gains 1 electron. Therefore , it electron becomes 18 in number.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>4","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"A hydrogen atom which has lost an electron contains","images":[],"options":{"A":"one proton only","B":"B one neutron only","C":"one proton and one neutron","D":"one proton , one electron and neutron."},"answer":"A","explanation":"Hydrogen atom is represented as 11H , meaning 1 Proton , 1electron , 0 neutron , so if it loses one electron , it becomes ,1 proton, 0 electron ,0 neutron","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>5","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"Which of the following element has a ground state electronic configuration with an incomplete penultimate shell?","images":[],"options":{"A":"iron","B":"sodium","C":"Aluminium","D":"calcium"},"answer":"A","explanation":"26Fe  The electronic configuration is     Since the 4s orbitals are higher in energy than Orbitals, therefore it becomes [Ar]3d64S2  Th penultimate shell 3d has incomplete electrons of 6 instead of 10 electrons, which is its maximum number of electron.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>6","subject":"Chemistry","year":"2002","type":"Objective","topic":"STRUCTURE OF THE ATOM : GROSS FEATURES OF THE ATOM","question":"The conclusion from Rutherford's alpha scattering experiment is that","images":[],"options":{"A":"atoms are mostly empty space with small nucleus","B":"emission from radioactive substance consist of three main components","C":"there is a nuclear pull on orbital","D":"electron are deflected by magnetic and electic field"},"answer":"A","explanation":"Alpha scattering experiment told us that the atom is an hollow empty space because most of the bombarded alpha particles went through the gold foil undeviated . However , few of it were deflected which reveals tht the atom consist of a small nucleus which has similar charge with the alpha particles.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>7","subject":"Chemistry","year":"2002","type":"Objective","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z    which of the letters indicate element which exist as diatomic gases","images":[],"options":{"A":"W and Z","B":"M and J","C":"M and Y","D":"Y and Q"},"answer":"C","explanation":"All the group 7 are diatomic but not all are gases, so M is a period III which is Cl2, a greenish yellow gas .Also Y is H2, a colourless gas","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>8","subject":"Chemistry","year":"2002","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   which of the following pairs of letters denotes elements containing thhe same number of electrons in their outermost shells","images":[],"options":{"A":"J and X","B":"M and Q","C":"W and Z","D":"W and Y"},"answer":"C","explanation":"Elements with the same number of electrons in their outermost shell are located in the same group","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>9","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   what letter represent an element that participate in covalent rather than ionic bonding?","images":[],"options":{"A":"x","B":"Q","C":"Z","D":"J"},"answer":"A","explanation":"Groups 3,4 and 5 elements participates in covalent bonding while groups ,1,2,6 and 7 are ionic","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>10","subject":"Chemistry","year":"2002","type":"Objective","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"use the following portion of the periodic table to answer  I II III IV V VI VII VIIIY       w  J  X    Q      M Z   Which of the letter represent an alkaline earth metal?","images":[],"options":{"A":"M","B":"Q","C":"J","D":"X"},"answer":"C","explanation":"In the periodic table, alkaline earth metals are found in Group II. Therefore, J, which is in Group II, represents an alkaline earth metal.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>11","subject":"Chemistry","year":"2002","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"An element Y as the electronic configuration 1s22s22p63s23p4 to what period does it belong in the periodic table?","images":[],"options":{"A":"3","B":"4","C":"5","D":"6"},"answer":"A","explanation":"The element is 2+2+6+2+4 = 16  i.e sulphur  16S : 2,8,6. since it has 3 shells i.e K,Lm shells, then it belongs to period table","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>12","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"If a metal R form a compound with formula R(NO3)2, the formula of its tetraoxosulphate(IV) is","images":[],"options":{"A":"R(SO4)2","B":"RSO4","C":"R2SO6","D":"R2(SO4)3"},"answer":"B","explanation":"R(NO3)2 when dissociated will be R2+ NO3-. So,when R2+ combines with SO42-, it will be RSO4 after valence crossing must taking place","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>13","subject":"Chemistry","year":"2002","type":"Objective","topic":"STATES OF MATTER : GASES","question":"Which of the following decrease when a given mass of gas is compressed to half its initial volume?","images":[],"options":{"A":"Average intermolecular distance","B":"Frequency of collisions","C":"Number of molecules present","D":"Atomic radius of each particle"},"answer":"A","explanation":"When the volumes is half (B), the number of molecules however remains the same but the frequency of collision increass which in turn increases pressure. From the diagram . distance between molecules have been reduced due to less space","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>14","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE","question":"What volume of hydrogen will be produced if 100cm3 of ammonia is completely decomposed at constant temperature and pressure ?. the equation for the reaction is 2NH3(g) \u2192 N2(g) + 3H2(g)","images":[],"options":{"A":"50cm3","B":"150cm3","C":"200cm3","D":"300cm3"},"answer":"B","explanation":"2NH3 \u2192 N2 + 3H2  2 moles of NH3 \u2192 3 moles of H2  100cm3 wll give x of H2  2x = 100 x 3  x = 150cm3","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>15","subject":"Chemistry","year":"2002","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"calculate the mass of chlorine gas which occupies a volume of 1.12 dm3 at s.t.p  [Cl = 35.5; 1 mole of gas occupies 22.4 dm at s.t.p]","images":[],"options":{"A":"1.80g","B":"3.55g","C":"7.10g","D":"15.50g"},"answer":"B","explanation":"Noofmole,n=mass,mmolar mass,MM  Also,n=Volume,vmolar volume,MV  n=1.1222.4=0.05mol  Fromn=mMM0.05=m71  m = 0.05 x 71   = 3.55 g","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2002>16","subject":"Chemistry","year":"2002","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"Determine the mass of sulphur(IV) oxide obtained when 91.0 g of oxygen reacts completely with sulphur according to the following  equation.  S(s) + O2(g) \u2192 SO2(g) [S = 32; O = 16]","images":[],"options":{"A":"123g","B":"139g","C":"155g","D":"182g"},"answer":"D","explanation":"Ss + O2g \u2192 SOg  32gmol-1 of S reacts with O2 to roduce 64gmol-1 of SO2  91g of S reacts with O2 to produce xg of SO2  xg=91x6432   = 1182g","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>17","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"The gas off when NH4Cl is heat with an alkali is","images":[],"options":{"A":"H2","B":"Cl2","C":"N2","D":"NH3"},"answer":"D","explanation":"When ammonium chloride (NH4Cl) is heated with an alkali, the gas evolved is ammonia (NH3). This is because the alkali provides a source of hydroxide ions (OH-) which react with the ammonium ions (NH4+) in the ammonium chloride to produce water (H2O) and ammonia gas. The reaction can be represented as follows: NH4Cl + OH- \u2192 NH3(g) + H2O. Therefore, the correct answer is NH3.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>18","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"A major factor considered in selecting a suitable method for preparing a simple salt is its","images":[],"options":{"A":"crystalline form","B":"melting point","C":"reactivity with dilute acids","D":"solubility in water"},"answer":"D","explanation":"The solubility of a salt in water is a major factor considered in selecting a suitable method for its preparation. This is because the solubility of the salt determines whether it can be prepared by a precipitation reaction, which involves mixing two solutions to form a precipitate (an insoluble salt), or by an evaporation method, which involves dissolving the salt in water and then evaporating the water to leave behind the salt.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>19","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Which of the following acids forms normal salts only","images":[],"options":{"A":"tetraoxosulphate (VI)acids","B":"Trioxosulphate(IV) acid","C":"Tetraoxophosphate(V)acid","D":"Trioxonitrate(V)acid"},"answer":"D","explanation":"Monobasic acids will give rise to normal salt acidic salt . HNO3 is the only monobasic acid the options.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>20","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"A substance is said to be hygroscopic if it absorbs","images":[],"options":{"A":"water from the atmosphere to form a solution","B":"heat from the surounding","C":"carbon(IV)oxide from the atmosphere","D":"moisture from the atosphere without dissolving"},"answer":"D","explanation":"A substance is said to be hygroscopic if it absorbs moisture from the atmosphere without dissolving. Hygroscopic substances have a high affinity for water molecules and can attract and hold water molecules from the surrounding environment. However, they do not dissolve in the absorbed water. Instead, they may form a solution if the amount of water absorbed is sufficient. The other options do not correctly define a hygroscopic substance.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>21","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"which of the following substance increases in mass when heated in air?","images":[],"options":{"A":"sodium chloride","B":"iodine crystals","C":"magnesium ribbon","D":"copper (II) oxide"},"answer":"C","explanation":"When magnesium ribbon is heated in air, it reacts with oxygen to form magnesium oxide. This reaction is an oxidation reaction, where magnesium is oxidized to magnesium oxide. The mass of the magnesium ribbon increases because oxygen from the air is being added to the magnesium.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>22","subject":"Chemistry","year":"2002","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calculate the mass of sodium hydroxide in 5.00 dm3 of a 0.125 mol dm-3 solution [NaOH = 40g mol-1]","images":[],"options":{"A":"0.0156g","B":"0.625g","C":"1.00g","D":"25.0g"},"answer":"D","explanation":"Molar mass of NaOH =23+16g + 1 = 40g/mol  No of mole , n  = concentration , c x volume v\\n = 0.125 x 5   = 0.625 mol  Fromn=Massmolar mass  0.625=m40  m = 40 x 0.625   = 25g","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>23","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Which of the following salt solution will have a pH greater than 7?","images":[],"options":{"A":"NaCl(aq)","B":"Na2CO3(aq)","C":"Na2SO(aq)","D":"NaHSO4(aq)"},"answer":"B","explanation":"NaCl  +H2O   \u21cc   NaOH + HCl  NaCO3 + H2O \u21cc NaOH + H2CO3  Na2SO4 + H2O \u21cc NaOH + H2SO4  NaHSO4 + H2O \u21cc NaOH + H2SO4  Only option B gives a strong base and weak acid .Hence a strong base and a weak acid gives a salt which is basic  i.e has a pH greater than 7","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>24","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"What will happen if more heat is applied to the followig system at equilibrium?  X2(aq) + 3y \u21cb 2XY3(g) ; \u2206H = -xkJmol-1","images":[],"options":{"A":"The yield of XY, will increase","B":"more of XY, will decompose","C":"more of XY, will react","D":"The forward reaction will go to completion"},"answer":"B","explanation":"Since the reaction is exothermic i.e \u2206H \u227a 0 ncreases in temperature favours the backward reaction , it should be noted that increase in temperature favours a side that is endothermic which decrease in temperature favours the side that is exothermic","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>25","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"What is the expression for the equilibrum contant (Kc) for the following reaction ?  N2(g) + O2(g) \u21cb 2NO(g)","images":[],"options":{"A":"(NO)2(N2)+(O2)","B":"(2NO)2(N2)(O2)","C":"(N2)+(O2)2(NO)2","D":"(NO)2(N2)(O2)"},"answer":"D","explanation":"N2(g) +O2(g) \u21cb 2NO(g)  Equilibriumconstant,kc=(NO)2(N2)(O2)  in determining equilibrium constant , only gaseous and aqueous substances are considered.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2002>26","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Equal amount of marble chip react separately with 100cm3 of hydrochloric acid of different concentrations if all the marble chips reacted, which of the following reamined the same in each case.","images":[],"options":{"A":"Average rate of evolution of gas","B":"total mass of gas evolved during the reaction","C":"time taken for the reaction to reach completion","D":"initial reaction rates"},"answer":"B","explanation":"The total mass of gas evolved during the reaction will remain the same in each case. This is because the amount of marble chips is the same in each case, and the reaction goes to completion. Therefore, the same amount of gas will be produced in each case, regardless of the concentration of the hydrochloric acid.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>27","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"CuSO4.5H2O can be obtained from an aqueous solution of copper (II) tetraoxosulphate(VI) by","images":[],"options":{"A":"evapouration to dryness","B":"using chromatography","C":"precipitation","D":"crytallization"},"answer":"D","explanation":"Crystallization is a separation technique that is used to separate a solid that has dissolved in a liquid and made a solution. The solution is warmed in an open container, allowing the solvent to evaporate, leaving a saturated solution. When the saturated solution cools, the solid comes out of solution and crystals form. In this case, CuSO4.5H2O can be obtained from an aqueous solution of copper (II) tetraoxosulphate(VI) by crystallization.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>28","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Which of the following compound will leave a metal residue when heated?","images":[],"options":{"A":"CU(NO3)2","B":"AgNO3","C":"K2CO3","D":"CaCO3"},"answer":"B","explanation":"Cu(NO3)2 \u2192\u2206CuO + NO2 + O2  AgNO3 \u2192\u2206Ag + NO2 + O2  K2CO3 \u2192\u2206 can't decompose   CaCO3 \u2192\u2206CaO + CO2","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>29","subject":"Chemistry","year":"2002","type":"Objective","topic":"METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS","question":"A visible change is observed when a strip of iron is placed in an aqueous solution of","images":[],"options":{"A":"FeSO4","B":"ZnSO4","C":"CuSO4","D":"MgSO4"},"answer":"C","explanation":"When a strip of iron is placed in an aqueous solution of copper(II) sulfate (CuSO4), a visible change is observed. This is due to a displacement reaction where iron displaces copper from copper sulfate solution to form iron sulfate (FeSO4) and copper (Cu). The blue solution of copper sulfate turns green due to the formation of iron sulfate and reddish-brown copper is deposited.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>30","subject":"Chemistry","year":"2002","type":"Objective","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"Consider the following   Cr2O2-7(aq) + 14H+(aq) + 6e- \u21922Cr3+(aq) + 7H2O(l)  The oxidation number of chromium changes from","images":[],"options":{"A":"-2 to +3","B":"-2 to +6","C":"+6 to +3","D":"+7 to +6"},"answer":"C","explanation":"Cr2O72- + 14H+ + 6e- \u21922Cr3+ + 7H2O  to get the oxidation state in Cr2O72-  2Cr + (-2 x 7) = 2  2Cr = 12  Cr = 12/2  Cr = +6  the oxidation state of Cr in Cr3+ is +3  The oxidation number of Cr chnages from +6 to +3","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>31","subject":"Chemistry","year":"2002","type":"Objective","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Which of the following ions require the largest quantity of electricty for discharge at an electrodes?","images":[],"options":{"A":"2.0 mole of Q3+","B":"2.5 mole of R2+","C":"3.0 mole of T-","D":"4.0 mole of Y-"},"answer":"A","explanation":"1 mole of Q3+ \u2192 3 faraday  (since 1e- = 1 faraday)  2 moles of Q3+ will need  \u21922 x 3F  = 6F  2 moles of Q3+ will require the largest quantity of electricity","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2002>32","subject":"Chemistry","year":"2002","type":"Objective","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"If two metallic ions of the same concentration migrate to graphite  cathode, this one that would be preferentially discharged is the one that has the","images":[],"options":{"A":"A smaller mass","B":"lower electrical","C":"greater stability in solution","D":"Stronger tendency to acdept electrons"},"answer":"D","explanation":"Factors that affect is charge of ion are concentrations, position of ion the electrochemical series and nature of the electrode. The position of ion in the in the electrochmical series is th tendency of the ion to accept electrons to become a neutral atom.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>33","subject":"Chemistry","year":"2002","type":"Objective","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"When concentrated sodium chlorine solution is electrolysed using inert electrodes, the products are","images":[],"options":{"A":"oxygen and hydrogen","B":"hydrogen and chlorine","C":"sodium and oxygen","D":"sodium and chlorine"},"answer":"B","explanation":"At the cathode :  Na+ and H+ migrate to the cathode where H+ is discharged because it is lower in the electrochemical series.  2H+ + 2e- \u2192H2  At the anode :  cl- and OH- migrate to anode where C- is discharged because of its concentration   2Cl- \u2192Cl2 + 2e-  The products are H2 and Cl2","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>34","subject":"Chemistry","year":"2002","type":"Objective","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"Which of the following processes takes place during the production of margarine from vegetable oils?","images":[],"options":{"A":"Esterification","B":"hydrolysis","C":"hydrogenation","D":"saponification"},"answer":"C","explanation":"The process that takes place during the production of margarine from vegetable oils is hydrogenation. Hydrogenation is a chemical reaction between molecular hydrogen and another compound or element, usually in the presence of a catalyst. In the case of margarine production, the vegetable oils (which are unsaturated fats) are hydrogenated to convert them into saturated fats, which are solid at room temperature.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>35","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Which of the following compouds can be represented by molecular formula C2H6O","images":[],"options":{"A":"Propanol","B":"Ethanol","C":"methanoic acid","D":"Glucose"},"answer":"B","explanation":"C2H6O  can be written as C2H5OH which is ethanol which follows the general molecular formular of alkanol CnH2n+1OH","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>36","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKYNES","question":"When alkynes are hydrogenated completely, they produced compounds with the generals molecular formula","images":[],"options":{"A":"CnHn","B":"CnH2n+2","C":"CnH2n","D":"CnH2n-2"},"answer":"B","explanation":"Hydrogenation of Alkynesgives Alkene , further hydrogenation gives Alkanes  Taking ethyne (C2H2) as a case study  C2H2 \u2192C2H4 (ethene)  C2H4 + H2 \u2192 C2H6  Alkanes have general molecular formular CnH2n+2","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>37","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"The following compound are hydrocarbons except","images":[],"options":{"A":"methylpropanoate","B":"2-methylbutane","C":"benzene","D":"cyclohexane"},"answer":"A","explanation":"Hydrocarbons are compounds that have hydrogen and carbons Only. Alkanoates are writte as RCOOR . hence , they do not have only carbon and hydrogen.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>38","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKENES","question":"The reaction between ethene and chlorine to form 1,2-dichloroethane is","images":[],"options":{"A":"oxidation","B":"polymerization","C":"addition","D":"substitution"},"answer":"C","explanation":"Addition reaction is undergone by unsaturated hydrocarbon . The bond is broken and more saturated hydrocarbon is formed","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>39","subject":"Chemistry","year":"2002","type":"Objective","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS","question":"Which of the following statement about soapless detergents is correct? they","images":[],"options":{"A":"lather readily with hard water","B":"increase the surface tension of water","C":"caused hydrolysis of salts in water","D":"form a curdy precipitate with soft water"},"answer":"A","explanation":"Soapless detergents, also known as synthetic detergents, are surfactants that do not form a precipitate with hard water. They lather readily with hard water because they do not react with the calcium and magnesium ions in hard water to form insoluble salts, unlike soaps. This makes them more effective cleaning agents in hard water.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>40","subject":"Chemistry","year":"2002","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Determine the molar mass of the following compounds  [H = 1; C = 12; O = 16]","images":["data:image/png;base64,"],"options":{"A":"45g mol-1","B":"61g mol-1","C":"122g mol-1","D":"123g mol-3"},"answer":"C","explanation":"The ring is a benzene (C6H6) ring in which one hydrogen aomhas been replaced with (CooH).The molecular formular can be written as C6H5COOH.The molecular formula can be written as C6H5COOH  Molar mass = (12 x 6) + (1 x 5) + 12 +16 + 1   122 g/mol","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>41","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS","question":"Which of the following types of alkanols undergo oxidation to produce alkanoic acids?  I. primary alkanols  II. secondary alkanols  III. Tetiary alkanols","images":[],"options":{"A":"I,II and III","B":"I and II only","C":"II only","D":"I only"},"answer":"D","explanation":"Primary alkanols udergo oxidation to give alkanals and finally alkanoic acid.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>42","subject":"Chemistry","year":"2002","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"A suitable reagent for distinguishing between ethanoic acids and ethanol is","images":[],"options":{"A":"bromine water","B":"Fehling`s solution","C":"sodium hydrogentrioxocarbonate (IV)","D":"ammoniacal silver trioxonitrate (V)."},"answer":"C","explanation":"Sodium hydrogentrioxocarbonate (IV) is a suitable reagent for distinguishing between ethanoic acids and ethanol. Ethanoic acid reacts with Sodium hydrogentrioxocarbonate (IV) to produce carbon dioxide gas that can be observed as effervescence, while ethanol does not react.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>43","subject":"Chemistry","year":"2002","type":"Objective","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"The reaction of sucrose with HCl Produces","images":[],"options":{"A":"an alkanoate","B":"glucose and fructose","C":"a black mass of carbon","D":"a polysaccharide"},"answer":"B","explanation":"Sucrose is protonated by Hcl then undergoes hydrolysis reaction to yield glucose and frutose as a final products.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>44","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"use the structue to answer question below      What is the IUPAC name of the compound with this structure","images":["data:image/png;base64,"],"options":{"A":"3-methylbutane","B":"3-methylpentane","C":"2-methylbutane","D":"2-methylpropane"},"answer":"C","explanation":"It is an alkane family because of carbon to carbon single throughout . The longest carbon to carbon chain consist of 4 carbon i.e butane , the attachment CH3(methyl) is on the 2nd and 3rd carbon when numbered L-R and R-L respectively , the rule says a smaller value is choosen .The name is 2-methylbutane","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>45","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"use the structue to answer question below    Which of the following compounds is its structural isomer","images":["data:image/png;base64,"],"options":{"A":"2,2-dimethylpropane","B":"2-ethylpropane","C":"1,2 dimethyl propane","D":"2 - methylpentane"},"answer":"A","explanation":"2,2-dimethylpropane     2,2-Dimethylpropane is a branched-chain alkane and is a structural isomer of pentane.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>46","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"The energy value of petrol can be determine by a","images":[],"options":{"A":"bomb calorimeter","B":"catalytic cracker","C":"fractionating column","D":"thermometer"},"answer":"A","explanation":"The energy level of organic compound is the mass content according to Albert Einstein.  E = \u2206mc2.  Bomb calorimeter is a closed rigid vessel that can used to determine the heat of fraction of a liquid or solid.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>47","subject":"Chemistry","year":"2002","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"use the solubility curve of X and Z       Which of the following statement about X and Z is correct?","images":["data:image/jpeg;base64,"],"options":{"A":"X is the more soluble solidat all temperatures","B":"X and z are insoluble at 0\u2218C","C":"0.20 mol dm-3 solution of Z at 10\u2218C is unsaturated","D":"Z is more soluble than X at temperature below 20\u2218C"},"answer":"D","explanation":"At a temperature below 20\u2218c, the solubility of Z is around 0.20moldm-3 while that of X is less than that.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2002>48","subject":"Chemistry","year":"2002","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"use the solubility curve of X and Z     What is the solubility of Z at 50\u2218C?","images":["data:image/jpeg;base64,"],"options":{"A":"0.20 mol dm-3","B":"0.25 mol dm-3","C":"0.35 mol-3","D":"0.50 mol dm-3"},"answer":"D","explanation":"This is determined by tracing 50\u2218 to Z  curve and tracing it solubility axis.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2002>49","subject":"Chemistry","year":"2002","type":"Objective","topic":"METALS AND THEIR COMPOUNDS : REACTIVITY OF IRON AND ALUMINIUM WITH AIR, WATER AND ACIDS","question":"iron is often galvanized in order to","images":[],"options":{"A":"makes it more malleable","B":"remove the impurities in it","C":"protect it against corrosion","D":"render it passive"},"answer":"C","explanation":"Iron is often galvanized to protect it against corrosion. Galvanization is the process of applying a protective zinc coating to iron or steel, to prevent rusting. The most common method is hot-dip galvanization, in which the parts are submerged in a bath of molten zinc.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2002>50","subject":"Chemistry","year":"2002","type":"Objective","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"One of the methods used for combating air pollution is","images":[],"options":{"A":"burning of solid waste","B":"provision of sanitary land fills","C":"legislation against some industrial practices","D":"scavenging of refuse dumps"},"answer":"C","explanation":"One of the methods used for combating air pollution is legislation against some industrial practices. This can include laws that regulate the amount of pollutants that can be released into the air, require the use of certain pollution control technologies, or mandate the cleanup of polluted areas. These laws can be enforced by government agencies and can result in penalties for non-compliance.","marks":"1","difficulty":"1"}];